mapper.select:
SELECT COUNT(*) FROM (
    SELECT 1 FROM family f
    WHERE f.id = #{familyId} AND f.del_flag = 0
    AND (
        EXISTS (
            SELECT 1 FROM family_admin fa
            WHERE fa.family_id = COALESCE(f.root_id, f.id)
            AND fa.user_id = #{userId}
            AND fa.role IN ('super_admin','admin')
        )
        OR f.founder_id = #{userId}
        OR f.chief_id = #{userId}
        OR EXISTS (SELECT 1 FROM family_member m WHERE m.family_id = f.id AND m.user_id = #{userId} AND m.del_flag = 0)
    )
    LIMIT 1
) x

SELECT COUNT(*) FROM (
    SELECT 1 FROM family f
    WHERE f.del_flag = 0
    AND COALESCE(f.root_id, f.id) = (
        SELECT COALESCE(root_id, id) FROM family WHERE id = #{tombFamilyId} AND del_flag = 0 LIMIT 1
    )
    AND (
        f.founder_id = #{userId}
        OR f.chief_id = #{userId}
        OR EXISTS (SELECT 1 FROM family_member m WHERE m.family_id = f.id AND m.user_id = #{userId} AND m.del_flag = 0)
        OR EXISTS (SELECT 1 FROM family_admin fa WHERE fa.family_id = COALESCE(f.root_id, f.id) AND fa.user_id = #{userId} AND fa.role IN ('super_admin','admin'))
    )
    LIMIT 1
) x
